#!/bin/bash
ros2 launch rtabmap_launch rtabmap.launch.py rgb_topic:=/spot/camera/frontleft/image depth_topic:=/spot/depth_registered/frontleft/image camera_info_topic:=/spot/camera/frontleft/camera_info frame_id:=spot/frontleft_fisheye base_frame_id:=spot/body odom_frame_id:=spot/odom odom_topic:=/spot/odometry visual_odometry:=false approx_sync:=true approx_sync_max_interval:=1.0 subscribe_depth:=true subscribe_rgb:=true rviz:=false database_path:=/root/spot_maps/rtabmap.db rtabmap_args:="--delete_db_on_start --Vis/MinInliers 6 --RGBD/LocalLoopDetectionMaxDiff 2.0 --RGBD/OptimizeMaxError 4.0 --Grid/3D false --Grid/FromDepth true --Grid/RangeMax 5.0 --Grid/FootprintHeight 0.5 --Grid/CellSize 0.05"
